const CAT_LABELS = [
  { id:"home",           label:"Home",           icon:"🏠" },
  { id:"work",           label:"Work",           icon:"👷" },
  { id:"businesses",     label:"Businesses",     icon:"🏢" },
  { id:"family",         label:"Family",         icon:"👨‍👩‍👧‍👦" },
  { id:"shopping",       label:"Shopping",       icon:"🛒" },
  { id:"transportation", label:"Transportation", icon:"🚌" },
];

// ── Main App ──────────────────────────────────────────────────────────────
export default function App() {
  const [activeCatId, setActiveCatId] = useState("home");
  const [activeSceneIdx, setActiveSceneIdx] = useState(0);
  const [activeScene, setActiveScene] = useState(ALL_SCENES["home"][0]);
  const [selectedHotspot, setSelectedHotspot] = useState(null);
  const [noteOpen, setNoteOpen] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState(false);
  const speakRef = useRef(null);

  const scenes = ALL_SCENES[activeCatId] || [];
  // activeScene is set explicitly on thumb click — does NOT change on tab switch
  const scene = activeScene;

  const speak = useCallback((text) => {
    if (!("speechSynthesis" in window)) return;
    window.speechSynthesis.cancel();
    const u = new SpeechSynthesisUtterance(text);
    u.rate = 0.92;
    u.onstart = () => setIsSpeaking(true);
    u.onend   = () => setIsSpeaking(false);
    u.onerror = () => setIsSpeaking(false);
    window.speechSynthesis.speak(u);
  }, []);

  const stopSpeech = useCallback(() => {
    if ("speechSynthesis" in window) window.speechSynthesis.cancel();
    setIsSpeaking(false);
  }, []);

  const handleHotspot = (e, hs) => {
    e.stopPropagation();
    setNoteOpen(false);
    setSelectedHotspot(hs);
  };

  const handleDeselect = () => {
    setSelectedHotspot(null);
    setNoteOpen(false);
    stopSpeech();
  };

  const handlePlay = (e) => {
    e.stopPropagation();
    if (isSpeaking) { stopSpeech(); return; }
    if (noteOpen && scene) { speak(scene.note); return; }
    if (selectedHotspot)   { speak(selectedHotspot.label); return; }
  };

  const handleNoteToggle = (e) => {
    e.stopPropagation();
    stopSpeech();
    setNoteOpen((prev) => !prev);
    setSelectedHotspot(null);
  };

  const handleCategoryClick = (id) => {
    setActiveCatId(id);
    setActiveSceneIdx(0);
    // deliberately do NOT update activeScene — main image stays
    setSelectedHotspot(null);
    setNoteOpen(false);
    stopSpeech();
  };

  const handleThumbClick = (idx) => {
    const sc = ALL_SCENES[activeCatId]?.[idx];
    if (sc) setActiveScene(sc);
    setActiveSceneIdx(idx);
    setSelectedHotspot(null);
    setNoteOpen(false);
    stopSpeech();
  };

  const labelText = noteOpen && scene
    ? scene.note
    : selectedHotspot
      ? selectedHotspot.label
      : scenes.length === 0
        ? "No scenes in this category yet"
        : "Tap an area in the scene…";

  return (
    <div
      onClick={handleDeselect}
      style={{
        fontFamily: "'DM Sans', sans-serif",
        background: "#ececec",
        height: "100dvh",
        maxHeight: "100dvh",
        display: "flex",
        flexDirection: "column",
        userSelect: "none",
        overflow: "hidden",
        position: "fixed",
        inset: 0,
      }}
    >
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=DM+Sans:wght@400;500;600;700&display=swap');
        * { box-sizing: border-box; }
        button { font-family: inherit; touch-action: manipulation; }
        .cat-tab {
          cursor: pointer;
          padding: 10px 12px;
          border-radius: 10px;
          font-size: clamp(16px, 1.6vw, 19px);
          font-weight: 500;
          background: #fff;
          border: 2px solid #ddd;
          transition: all 0.15s;
          color: #333;
          display: flex;
          flex-direction: column;
          align-items: center;
          justify-content: center;
          gap: 3px;
          min-width: clamp(90px, 9vw, 140px);
          min-height: 54px;
          height: auto;
          touch-action: manipulation;
          flex-shrink: 0;
        }
        .cat-tab:hover { background: #e8f0fe; border-color: #aac4f5; }
        .cat-tab.active {
          background: #fff;
          border: 2.5px solid #5b9bd5;
          color: #1a4a8a;
          font-weight: 700;
        }
        .cat-icon {
          font-size: clamp(22px, 2.4vw, 30px);
          line-height: 1;
        }
        .cat-label {
          display: flex;
          flex-direction: row;
          align-items: baseline;
          gap: 4px;
          line-height: 1.2;
          white-space: nowrap;
        }
        .cat-count {
          font-size: clamp(16px, 1.4vw, 18px);
          color: #7a9cc8;
          font-weight: 400;
        }
        .thumb-item {
          cursor: pointer;
          border-radius: 8px;
          overflow: hidden;
          border: 3px solid transparent;
          transition: border 0.15s, transform 0.1s;
          flex-shrink: 0;
          background: #ccc;
          touch-action: manipulation;
        }
        .thumb-item.active { border-color: #5b9bd5; }
        .thumb-item img { width: 100%; height: clamp(80px, 10vw, 140px); object-fit: cover; display: block; }
        .hotspot-zone {
          position: absolute;
          border-radius: 6px;
          cursor: pointer;
          border: 2px solid rgba(255,255,255,0.5);
          transition: background 0.15s, border-color 0.15s;
          box-sizing: border-box;
          touch-action: manipulation;
        }
        .hotspot-zone:hover { background: rgba(255,255,255,0.15); border-color: rgba(255,255,255,0.75); }
        .hotspot-zone.selected {
          background: rgba(91,155,213,0.25);
          border-color: rgba(91,155,213,0.9);
          border-width: 2.5px;
        }
        .pencil-btn {
          position: absolute;
          top: 12px; left: 12px;
          width: 48px; height: 48px;
          border-radius: 10px;
          background: rgba(50,50,50,0.72);
          border: none;
          cursor: pointer;
          display: flex;
          align-items: center;
          justify-content: center;
          transition: background 0.15s;
          z-index: 10;
          backdrop-filter: blur(4px);
          touch-action: manipulation;
        }
        .pencil-btn.active { background: rgba(91,155,213,0.85); }
        .play-btn {
          display: flex;
          align-items: center;
          gap: 7px;
          background: #fff;
          border: 2px solid #ccc;
          border-radius: 10px;
          padding: 0 22px;
          font-size: clamp(16px, 1.6vw, 20px);
          font-weight: 600;
          cursor: pointer;
          transition: background 0.15s, border-color 0.15s;
          flex-shrink: 0;
          color: #222;
          height: 100%;
          min-width: 90px;
          touch-action: manipulation;
        }
        .play-btn:hover { background: #e8f4ff; border-color: #5b9bd5; }
        .play-btn:disabled { opacity: 0.45; cursor: default; }
        .empty-state {
          flex: 1;
          display: flex;
          align-items: center;
          justify-content: center;
          color: #888;
          font-size: 18px;
          font-style: italic;
          background: #2a2a2a;
        }
      `}</style>

      {/* ── Top bar ── */}
      <div
        onClick={(e) => e.stopPropagation()}
        style={{
          background: "#fff",
          borderBottom: "1px solid #ddd",
          padding: "10px 12px",
          display: "flex",
          alignItems: "center",
          gap: 8,
          overflowX: "auto",
          flexShrink: 0,
          minHeight: "10vh",
          WebkitOverflowScrolling: "touch",
        }}
      >
        {/* Profile icon */}
        <div style={{ width: "calc(10vh - 16px)", height: "calc(10vh - 16px)", minWidth: 44, minHeight: 44, borderRadius: 10, background: "#c5cfe8", display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0, border: "2px solid #aabce8" }}>
          <svg width="26" height="26" viewBox="0 0 24 24" fill="none" stroke="#4a6fa5" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
            <path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2"/>
            <circle cx="12" cy="7" r="4"/>
          </svg>
        </div>

        {CAT_LABELS.map((cat) => (
          <button
            key={cat.id}
            className={`cat-tab${activeCatId === cat.id ? " active" : ""}`}
            onClick={() => handleCategoryClick(cat.id)}
          >
            <span className="cat-icon">{cat.icon}</span>
            <span className="cat-label">
              {cat.label}
              {activeCatId === cat.id && (
                <span className="cat-count"> ({(ALL_SCENES[cat.id] || []).length})</span>
              )}
            </span>
          </button>
        ))}
      </div>

      {/* ── Main content ── */}
      <div style={{ flex: 1, display: "flex", overflow: "hidden", minHeight: 0, height: 0 }}>

        {/* ── Scene viewer ── */}
        <div style={{ flex: 1, minWidth: 0, display: "flex", flexDirection: "column", background: "#111" }}>

          {/* Image + hotspots */}
          {scene ? (
            <div style={{ flex: 1, position: "relative", overflow: "hidden" }}>
              <img
                src={IMG_MAP[scene.img]}
                alt={scene.title}
                style={{ width: "100%", height: "100%", objectFit: "cover", display: "block" }}
                draggable={false}
              />
              {scene.hotspots.map((hs) => (
                <div
                  key={hs.id}
                  className={`hotspot-zone${selectedHotspot?.id === hs.id ? " selected" : ""}`}
                  style={{ left:`${hs.x}%`, top:`${hs.y}%`, width:`${hs.w}%`, height:`${hs.h}%` }}
                  onClick={(e) => handleHotspot(e, hs)}
                />
              ))}
              <button
                className={`pencil-btn${noteOpen ? " active" : ""}`}
                onClick={handleNoteToggle}
                title={noteOpen ? "Close note" : "Read scene note"}
              >
                <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="#fff" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                  <path d="M12 20h9"/>
                  <path d="M16.5 3.5a2.121 2.121 0 0 1 3 3L7 19l-4 1 1-4 12.5-12.5z"/>
                </svg>
              </button>
            </div>
          ) : (
            <div className="empty-state">No scenes yet</div>
          )}

          {/* ── Bottom bar ── */}
          <div
            onClick={(e) => e.stopPropagation()}
            style={{
              background: "rgba(255,255,255,0.94)",
              backdropFilter: "blur(6px)",
              borderTop: "1px solid #ddd",
              padding: "8px 14px",
              display: "flex",
              alignItems: "stretch",
              gap: 12,
              flexShrink: 0,
              height: "10vh",
              minHeight: 60,
            }}
          >
            {/* Label display */}
            <div style={{
              flex: 1,
              background: "#fff",
              border: `1.5px solid ${noteOpen ? "#5b9bd5" : "#dde3ec"}`,
              borderRadius: 10,
              display: "flex",
              alignItems: "center",
              padding: "0 14px",
              fontSize: noteOpen ? "clamp(16px, 1.6vw, 18px)" : "clamp(16px, 1.8vw, 22px)",
              color: (noteOpen || selectedHotspot) ? "#1a3a6a" : "#aaa",
              fontWeight: noteOpen ? 400 : (selectedHotspot ? 600 : 400),
              fontStyle: (!noteOpen && !selectedHotspot) ? "italic" : "normal",
              letterSpacing: 0.2,
              lineHeight: noteOpen ? 1.5 : 1.3,
              overflowY: noteOpen ? "auto" : "hidden",
            }}>
              {labelText}
            </div>

            {/* Play / Stop button */}
            <button
              className="play-btn"
              onClick={handlePlay}
              disabled={!selectedHotspot && !noteOpen}
              style={isSpeaking ? { borderColor: "#e05555", color: "#e05555" } : {}}
            >
              {isSpeaking ? "Stop" : "Play"}
              {isSpeaking ? (
                <svg width="17" height="17" viewBox="0 0 24 24" fill="currentColor" stroke="none">
                  <rect x="4" y="4" width="6" height="16" rx="1"/>
                  <rect x="14" y="4" width="6" height="16" rx="1"/>
                </svg>
              ) : (
                <svg width="17" height="17" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.2" strokeLinecap="round" strokeLinejoin="round">
                  <polygon points="11 5 6 9 2 9 2 15 6 15 11 19 11 5"/>
                  <path d="M19.07 4.93a10 10 0 0 1 0 14.14"/>
                  <path d="M15.54 8.46a5 5 0 0 1 0 7.07"/>
                </svg>
              )}
            </button>
          </div>
        </div>

        {/* ── Thumbnail strip ── */}
        <div
          onClick={(e) => e.stopPropagation()}
          style={{
            width: "15vw",
            minWidth: 110,
            maxWidth: 200,
            background: "#e2e2e2",
            borderLeft: "1px solid #ccc",
            display: "flex",
            flexDirection: "column",
            gap: 5,
            padding: "6px",
            overflowY: "auto",
            flexShrink: 0,
            WebkitOverflowScrolling: "touch",
          }}
        >
          {scenes.map((sc, idx) => (
            <div
              key={sc.id}
              className={`thumb-item${activeSceneIdx === idx ? " active" : ""}`}
              onClick={() => handleThumbClick(idx)}
            >
              <img src={IMG_MAP[sc.img]} alt={sc.title} />
            </div>
          ))}
          {scenes.length === 0 && (
            <div style={{ color:"#aaa", fontSize:12, textAlign:"center", padding:"12px 4px", fontStyle:"italic" }}>
              No scenes
            </div>
          )}
        </div>

      </div>
    </div>
  );
}
